170	    pub(crate) async fn connect_on_handshake(
171	        self,
172	        peer: SocketAddr,
173	        mut hs: HandShakeInfo,
174	    ) -> Result<SocketRef> {
175	        {
176	            let mut configuration = self.configuration.write().unwrap();
177	            if hs.max_packet_size > configuration.mss {
178	                hs.max_packet_size = configuration.mss;
179	            } else {
180	                configuration.mss = hs.max_packet_size;
181	            }
182	
183	            self.flow.write().unwrap().flow_window_size = hs.max_window_size;
184	            hs.max_window_size =
185	                std::cmp::min(configuration.rcv_buf_size, configuration.flight_flag_size);
186	        }
187	        // self.set_self_ip(hs.ip_address);
188	        hs.ip_address = peer.ip();
189	        hs.socket_id = self.socket_id;
190	
191	        // TODO: use network information cache to set RTT, bandwidth, etc.
192	
193	        {
194	            let mut rate_control = self.rate_control.write().unwrap();
195	            rate_control.init(
196	                self.configuration.read().unwrap().mss,
197	                &self.flow.read().unwrap(),
198	                self.state().curr_snd_seq_number,
199	            )
200	        }
201	
202	        *self.status.lock().unwrap() = UdtStatus::Connected;
203	
204	        let packet = UdtControlPacket::new_handshake(
205	            hs,
206	            self.peer_socket_id().expect("peer_socket_id not defined"),
207	        );
208	
209	        if let Some(mux) = self.multiplexer() {
210	            mux.rcv_queue.push_back(self.socket_id);
211	            mux.send_to(&peer, packet.into()).await?;
212	        }
213	
214	        let socket = Arc::new(self);
215	        Ok(socket)
216	    }
