675	    async fn process_data(&self, packet: UdtDataPacket) -> Result<()> {
676	        let now = Instant::now();
677	        {
678	            let mut state = self.state();
679	            state.last_rsp_time = now;
680	            state.pkt_count += 1;
681	        }
682	
683	        let seq_number = packet.header.seq_number;
684	
685	        {
686	            let mut flow = self.flow.write().unwrap();
687	            flow.on_pkt_arrival(now);
688	
689	            if seq_number.number() % PROBE_MODULO == 0 {
690	                flow.on_probe1_arrival();
691	            } else if seq_number.number() % PROBE_MODULO == 1 {
692	                flow.on_probe2_arrival();
693	            }
694	        }
695	
696	        // trace_rcv++
697	        // recv_total++
698	        let offset = seq_number - self.state().last_sent_ack;
699	        if offset < 0 {
700	            // seq number is too late
701	            return Ok(());
702	        }
703	
704	        let payload_len = {
705	            let mut rcv_buffer = self.rcv_buffer();
706	            let available_buf_size = rcv_buffer.get_available_buf_size();
707	            if available_buf_size < offset as u32 {
708	                if *UDT_DEBUG {
709	                    eprintln!("not enough space in rcv buffer");
710	                }
711	                return Ok(());
712	            }
713	
714	            let payload_len = packet.payload_len();
715	            rcv_buffer.insert(packet);
716	            payload_len
717	        };
718	
719	        if (seq_number - self.state().curr_rcv_seq_number) > 1 {
720	            // some packets have been lost in between
721	            let nak_packet = {
722	                let mut state = self.state();
723	                let curr_rcv_seq_number = state.curr_rcv_seq_number;
724	                state
725	                    .rcv_loss_list
726	                    .insert(curr_rcv_seq_number + 1, seq_number - 1);
727	
728	                // send NAK immediately
729	                let loss_list = {
730	                    if state.curr_rcv_seq_number + 1 == seq_number - 1 {
731	                        vec![(seq_number - 1).number()]
732	                    } else {
733	                        vec![
734	                            (state.curr_rcv_seq_number + 1).number() | 0x8000_0000,
735	                            (seq_number - 1).number(),
736	                        ]
737	                    }
738	                };
739	                UdtControlPacket::new_nak(loss_list, self.peer_socket_id().unwrap_or(0))
740	            };
741	            self.send_packet(nak_packet.into()).await?;
742	        }
743	
744	        if payload_len < self.get_max_payload_size() {
745	            self.state().next_ack_time = Instant::now();
746	        }
747	
748	        let mut state = self.state();
749	
750	        if seq_number - state.curr_rcv_seq_number > 0 {
751	            state.curr_rcv_seq_number = seq_number;
752	        } else {
753	            state.rcv_loss_list.remove(seq_number);
754	        }
755	
756	        Ok(())
757	    }
