1065	    pub(crate) fn poll_recv(&self, buf: &mut ReadBuf<'_>) -> Poll<Result<usize>> {
1066	        if self.socket_type != SocketType::Stream {
1067	            return Poll::Ready(Err(Error::new(
1068	                ErrorKind::InvalidInput,
1069	                "cannot recv on non-stream socket",
1070	            )));
1071	        }
1072	        let status = self.status();
1073	        if !status.is_alive() {
1074	            if !self.rcv_buffer().has_data_to_read() {
1075	                return Poll::Ready(Err(Error::new(
1076	                    ErrorKind::BrokenPipe,
1077	                    "connection was closed or broken",
1078	                )));
1079	            }
1080	        } else if status != UdtStatus::Connected {
1081	            return Poll::Ready(Err(Error::new(
1082	                ErrorKind::NotConnected,
1083	                "UDT socket not connected",
1084	            )));
1085	        }
1086	
1087	        if !self.rcv_buffer().has_data_to_read() {
1088	            return Poll::Pending;
1089	        }
1090	
1091	        if buf.remaining() == 0 {
1092	            return Poll::Ready(Ok(0));
1093	        }
1094	        let written = self.rcv_buffer().read_buffer(buf);
1095	        Poll::Ready(Ok(written))
1096	    }
