1118	
1119	        // TODO: register the current socket in the rendezvous queue
1120	        // This is used to temporarily store incoming handshakes and possibly retry connections, including for non-rendezvous connections.
1121	
1122	        let hs_packet = {
1123	            let configuration = self.configuration.read().unwrap();
1124	            let hs = HandShakeInfo {
